```javascript
const facts = [
    "Frogs have been around for over 200 million years!",
    "A frog's tongue can be longer than its body.",
    "Frogs absorb water through their skin.",
    "Some frogs can freeze solid and survive the winter.",
    "Frogs have no teeth on their lower jaw.",
    "The poison dart frog is so toxic that indigenous people used it on blow darts.",
    "Frogs can jump up to 20 times their body length.",
    "There are over 7,000 species of frogs worldwide.",
    "Frogs have been used as pets for over 100 years.",
    "The smallest frog is only 7.7mm long!",
    "Frogs can see in 3D, just like humans.",
    "A group of frogs is called an army.",
    "Frogs have been used as food in many cultures for centuries.",
    "The glass frog has transparent skin that reveals its organs.",
    "Frogs can live up to 40 years in captivity."
];

const factText = document.getElementById('fact-text');
const newFactBtn = document.getElementById('new-fact');

function showNewFact() {
    const randomIndex = Math.floor(Math.random() * facts.length);
    factText.textContent = facts[randomIndex];
    factText.style.opacity = 0;
    setTimeout(() => {
        factText.style.opacity = 1;
    }, 100);
}

newFactBtn.addEventListener('click', showNewFact);

document.querySelectorAll('.sound-frog').forEach(button => {
    button.addEventListener('click', function() {
        const sound = this.getAttribute('data-sound');
        this.textContent = `🐸 ${sound.charAt(0).toUpperCase() + sound.slice(1)}!`;
        this.style.background = '#ffeb3b';
        this.style.color = '#2e7d32';
        setTimeout(() => {
            this.textContent = `🐸 ${sound.charAt(0).toUpperCase() + sound.slice(1)}!`;
            this.style.background = '#81c784';
            this.style.color = 'white';
        }, 1000);
    });
});

document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
        e.preventDefault();
        const target = document.querySelector(this.getAttribute('href'));
        if (target) {
            target.scrollIntoView({ behavior: 'smooth' });
        }
    });
});
```

